/**
 * Get all sell products for static generation
 */
export function getAllProducts(): SellProduct[] {
  return sellProducts;
}

/**
 * Get a specific product by slug
 */
export function getProductBySlug(slug: string): SellProduct | undefined {
  return sellProducts.find((p) => p.slug === slug);
}

/**
 * Get all product slugs for generateStaticParams
 */
export function getAllProductSlugs(): string[] {
  return sellProducts.map((p) => p.slug);
}
